+	if err := os.WriteFile(leaseFile, []byte(content), 0644); err != nil {
+		t.Fatal(err)
+	}
+
+	rc := &ResourceCollector{
+		cfg:       config.DefaultConfig(),
+		leaseFile: leaseFile,
+		macToIP:   make(map[string]string),
